#!/usr/bin/env node
import fs from "node:fs";
import path from "node:path";

const root = process.cwd();

function write(relativePath, content) {
  const filePath = path.join(root, relativePath);
  fs.mkdirSync(path.dirname(filePath), { recursive: true });
  fs.writeFileSync(filePath, content, "utf8");
}

function read(relativePath) {
  const filePath = path.join(root, relativePath);
  if (!fs.existsSync(filePath)) return "";
  return fs.readFileSync(filePath, "utf8");
}

function patchHomepage() {
  const relativePath = "src/pages/Homepage.jsx";
  let content = read(relativePath);

  if (!content) {
    console.warn("⚠️ Não encontrei src/pages/Homepage.jsx. A saltar patch da homepage.");
    return;
  }

  const current = `      <HomeQuickActions
        onOpenCampaign={() => navigate("/EtiquetasCampanha")}
        onOpenArticles={() => navigate("/Etiquetas")}
        onOpenScan={() => navigate("/Etiquetas?mode=scan")}
        onOpenExcel={() => navigate("/EtiquetasCampanhaExcel")}
      />`;

  const next = `      <HomeQuickActions
        onOpenCampaign={() => navigate("/EtiquetasCampanha")}
        onOpenArticles={() => navigate("/Etiquetas")}
        onOpenScan={() => navigate("/Etiquetas?mode=scan")}
        onOpenDossiers={() => navigate("/OrcamentosDossiers")}
        onOpenExcel={() => navigate("/EtiquetasCampanhaExcel")}
      />`;

  if (content.includes(current)) {
    content = content.replace(current, next);
  } else if (!content.includes("onOpenDossiers")) {
    console.warn("⚠️ Não encontrei o bloco HomeQuickActions esperado. Confirma manualmente onOpenDossiers.");
  }

  write(relativePath, content);
}

function patchStylesImport() {
  const relativePath = "src/styles/styles.css";
  let content = read(relativePath);

  if (!content) {
    content = "";
  }

  if (!content.includes('@import "./promopilot.css";')) {
    content = `${content.trim()}\n@import "./promopilot.css";\n`;
  }

  write(relativePath, content);
}

write("src/brand/promopilot.js", "export const PROMOPILOT_BRAND = {\n  appName: \"PromoPilot\",\n  shortName: \"PP\",\n  descriptor: \"Retail Operations Cockpit\",\n  claim: \"Campanhas, etiquetas, artigos e dossiers comerciais num s\u00f3 cockpit.\",\n  company: \"SusiArte\",\n  versionLabel: \"Main\",\n};\n\nexport const PROMOPILOT_MODULES = [\n  {\n    key: \"campaigns\",\n    label: \"Campanhas\",\n    description: \"Produ\u00e7\u00e3o manual e autom\u00e1tica de etiquetas promocionais.\",\n  },\n  {\n    key: \"articles\",\n    label: \"Cat\u00e1logo\",\n    description: \"Pesquisa operacional por artigo, EAN, descri\u00e7\u00e3o e modelo.\",\n  },\n  {\n    key: \"dossiers\",\n    label: \"Dossiers\",\n    description: \"Transforma\u00e7\u00e3o de or\u00e7amentos em dossiers comerciais.\",\n  },\n  {\n    key: \"store\",\n    label: \"Loja\",\n    description: \"Ferramentas r\u00e1pidas para equipas de venda.\",\n  },\n];\n");
write("src/components/brand/PromoPilotMark.jsx", "import React from \"react\";\nimport { PROMOPILOT_BRAND } from \"../../brand/promopilot\";\n\nexport default function PromoPilotMark({\n  compact = false,\n  tone = \"dark\",\n  className = \"\",\n}) {\n  return (\n    <div className={`pp-brand-lockup pp-brand-lockup-${tone} ${compact ? \"pp-brand-compact\" : \"\"} ${className}`.trim()}>\n      <div className=\"pp-brand-mark\" aria-hidden=\"true\">\n        <span className=\"pp-brand-mark-dot\" />\n        <strong>PP</strong>\n      </div>\n\n      {!compact && (\n        <div className=\"pp-brand-copy\">\n          <span className=\"pp-brand-name\">{PROMOPILOT_BRAND.appName}</span>\n          <span className=\"pp-brand-descriptor\">{PROMOPILOT_BRAND.descriptor}</span>\n        </div>\n      )}\n    </div>\n  );\n}\n");
write("src/App.js", "import React, { Suspense, lazy, useMemo, useState } from \"react\";\nimport { Navigate, Route, Routes } from \"react-router-dom\";\nimport Sidebar from \"./components/Sidebar\";\nimport ProtectedRoute from \"./components/ProtectedRoute\";\nimport PromoPilotMark from \"./components/brand/PromoPilotMark\";\nimport { useAuth } from \"./context/AuthContext\";\nimport { PROMOPILOT_BRAND } from \"./brand/promopilot\";\nimport { resolveInitialRoute } from \"./utils/accessControl\";\nimport \"./styles/styles.css\";\n\nconst EtiquetasPage = lazy(() => import(\"./pages/EtiquetasCampanha\"));\nconst EtiquetasExcelPage = lazy(() => import(\"./pages/EtiquetasCampanhaExcel\"));\nconst Etiquetas = lazy(() => import(\"./pages/Etiquetas\"));\nconst Homepage = lazy(() => import(\"./pages/Homepage\"));\nconst Login = lazy(() => import(\"./pages/Login\"));\nconst OrcamentosDossiersPage = lazy(() => import(\"./pages/OrcamentosDossiers\"));\n\nfunction PageFallback() {\n  return (\n    <div className=\"pp-splash-screen\">\n      <div className=\"pp-splash-card\">\n        <PromoPilotMark tone=\"light\" />\n        <div className=\"pp-splash-loader\" aria-hidden=\"true\">\n          <span />\n        </div>\n        <p>A preparar cockpit operacional...</p>\n      </div>\n    </div>\n  );\n}\n\nexport default function App() {\n  const [menuAberto, setMenuAberto] = useState(false);\n  const { user, loadingAuth, loadingProfile, onboardingRequired } = useAuth();\n  const rotaInicial = useMemo(\n    () => resolveInitialRoute({ user, onboardingRequired }),\n    [user, onboardingRequired],\n  );\n\n  if (loadingAuth || (user && loadingProfile)) return <PageFallback />;\n\n  return (\n    <div className={user ? \"app pp-app-shell\" : \"app app-login pp-login-shell\"}>\n      {user && !onboardingRequired && (\n        <Sidebar\n          menuAberto={menuAberto}\n          setMenuAberto={setMenuAberto}\n          titulo={PROMOPILOT_BRAND.appName}\n        />\n      )}\n\n      <Suspense fallback={<PageFallback />}>\n        <Routes>\n          <Route path=\"/\" element={<Navigate to={rotaInicial} replace />} />\n          <Route path=\"/login\" element={<Login />} />\n          <Route path=\"/Homepage\" element={<ProtectedRoute><Homepage /></ProtectedRoute>} />\n          <Route path=\"/EtiquetasCampanha\" element={<ProtectedRoute><EtiquetasPage /></ProtectedRoute>} />\n          <Route path=\"/Etiquetas\" element={<ProtectedRoute><Etiquetas /></ProtectedRoute>} />\n          <Route path=\"/EtiquetasCampanhaExcel\" element={<ProtectedRoute><EtiquetasExcelPage /></ProtectedRoute>} />\n          <Route path=\"/OrcamentosDossiers\" element={<ProtectedRoute><OrcamentosDossiersPage /></ProtectedRoute>} />\n          <Route path=\"*\" element={<Navigate to={rotaInicial} replace />} />\n        </Routes>\n      </Suspense>\n    </div>\n  );\n}\n");
write("src/components/Sidebar.jsx", "import React, { useEffect, useMemo, useRef, useState } from \"react\";\nimport { Link, useLocation } from \"react-router-dom\";\nimport PromoPilotMark from \"./brand/PromoPilotMark\";\nimport { useAuth } from \"../context/AuthContext\";\nimport { PROMOPILOT_BRAND } from \"../brand/promopilot\";\nimport { getPasswordValidationMessage, isValidPassword } from \"../utils/validators\";\n\nexport default function Sidebar({\n  menuAberto,\n  setMenuAberto,\n  titulo = PROMOPILOT_BRAND.appName,\n}) {\n  const location = useLocation();\n  const { user, profile, signOut, updatePassword } = useAuth();\n\n  const [submenuEtiquetasAberto, setSubmenuEtiquetasAberto] = useState(false);\n  const [loadingLogout, setLoadingLogout] = useState(false);\n  const [menuContaAberto, setMenuContaAberto] = useState(false);\n  const [modalPasswordAberto, setModalPasswordAberto] = useState(false);\n  const [novaPassword, setNovaPassword] = useState(\"\");\n  const [confirmarPassword, setConfirmarPassword] = useState(\"\");\n  const [loadingPassword, setLoadingPassword] = useState(false);\n  const [erroPassword, setErroPassword] = useState(\"\");\n  const [sucessoPassword, setSucessoPassword] = useState(\"\");\n\n  const contaMenuRef = useRef(null);\n\n  const rotaEtiquetasAtiva = useMemo(() => {\n    return (\n      location.pathname === \"/Etiquetas\" ||\n      location.pathname === \"/EtiquetasCampanha\" ||\n      location.pathname === \"/EtiquetasCampanhaExcel\"\n    );\n  }, [location.pathname]);\n\n  const nomeUtilizador = useMemo(() => {\n    const nome = [profile?.first_name, profile?.last_name]\n      .map((value) => String(value || \"\").trim())\n      .filter(Boolean)\n      .join(\" \");\n\n    return nome || String(user?.email || \"\").trim() || \"Conta\";\n  }, [profile?.first_name, profile?.last_name, user?.email]);\n\n  const iniciaisUtilizador = useMemo(() => {\n    const chunks = String(nomeUtilizador || \"\")\n      .split(/\\s+/)\n      .filter(Boolean)\n      .slice(0, 2);\n\n    return chunks.map((chunk) => chunk[0]).join(\"\").toUpperCase() || \"PP\";\n  }, [nomeUtilizador]);\n\n  const lojaAtual = String(profile?.store || profile?.store_id || \"Opera\u00e7\u00e3o\").trim();\n\n  useEffect(() => {\n    if (rotaEtiquetasAtiva) setSubmenuEtiquetasAberto(true);\n  }, [rotaEtiquetasAtiva]);\n\n  useEffect(() => {\n    function handleKeyDown(e) {\n      if (e.key === \"Escape\") {\n        setMenuAberto(false);\n        setMenuContaAberto(false);\n        setModalPasswordAberto(false);\n      }\n    }\n\n    window.addEventListener(\"keydown\", handleKeyDown);\n    return () => window.removeEventListener(\"keydown\", handleKeyDown);\n  }, [setMenuAberto]);\n\n  useEffect(() => {\n    function handleClickOutside(event) {\n      if (contaMenuRef.current && !contaMenuRef.current.contains(event.target)) {\n        setMenuContaAberto(false);\n      }\n    }\n\n    document.addEventListener(\"mousedown\", handleClickOutside);\n    return () => document.removeEventListener(\"mousedown\", handleClickOutside);\n  }, []);\n\n  function fecharTudo() {\n    setMenuAberto(false);\n  }\n\n  function toggleSubmenu() {\n    setSubmenuEtiquetasAberto((prev) => !prev);\n  }\n\n  function isActive(path) {\n    if (path === \"/Homepage\") {\n      return location.pathname === \"/Homepage\" || location.pathname === \"/\";\n    }\n\n    return location.pathname === path;\n  }\n\n  function abrirModalPassword() {\n    setErroPassword(\"\");\n    setSucessoPassword(\"\");\n    setNovaPassword(\"\");\n    setConfirmarPassword(\"\");\n    setMenuContaAberto(false);\n    setModalPasswordAberto(true);\n  }\n\n  function fecharModalPassword() {\n    setModalPasswordAberto(false);\n    setErroPassword(\"\");\n    setSucessoPassword(\"\");\n    setNovaPassword(\"\");\n    setConfirmarPassword(\"\");\n  }\n\n  async function handleLogout() {\n    try {\n      setLoadingLogout(true);\n      await signOut();\n      setMenuContaAberto(false);\n      fecharTudo();\n    } catch (error) {\n      console.error(\"Erro ao sair:\", error.message);\n    } finally {\n      setLoadingLogout(false);\n    }\n  }\n\n  async function handleChangePassword(e) {\n    e.preventDefault();\n    setErroPassword(\"\");\n    setSucessoPassword(\"\");\n\n    const passwordTrimmed = String(novaPassword || \"\").trim();\n    const confirmTrimmed = String(confirmarPassword || \"\").trim();\n\n    if (!isValidPassword(passwordTrimmed)) {\n      setErroPassword(getPasswordValidationMessage(passwordTrimmed));\n      return;\n    }\n\n    if (passwordTrimmed !== confirmTrimmed) {\n      setErroPassword(\"As palavras-passe n\u00e3o coincidem.\");\n      return;\n    }\n\n    try {\n      setLoadingPassword(true);\n      await updatePassword(passwordTrimmed);\n      setSucessoPassword(\"Palavra-passe atualizada com sucesso.\");\n\n      setTimeout(() => {\n        fecharModalPassword();\n      }, 1200);\n    } catch (error) {\n      setErroPassword(error?.message || \"Erro ao atualizar a palavra-passe.\");\n    } finally {\n      setLoadingPassword(false);\n    }\n  }\n\n  return (\n    <>\n      <div className=\"topbar-site no-print\">\n        <button\n          type=\"button\"\n          className=\"menu-button\"\n          onClick={() => setMenuAberto(true)}\n          aria-label=\"Abrir menu\"\n          aria-expanded={menuAberto}\n          aria-controls=\"sidebar-navigation\"\n        >\n          <span />\n          <span />\n          <span />\n        </button>\n\n        <PromoPilotMark className=\"pp-topbar-brand\" />\n        <div className=\"topbar-title\">{titulo}</div>\n\n        <div className=\"topbar-context\">\n          <span className=\"topbar-context-label\">Ambiente</span>\n          <strong>{PROMOPILOT_BRAND.versionLabel}</strong>\n        </div>\n\n        <div className=\"topbar-spacer\" />\n\n        <div className=\"topbar-account\" ref={contaMenuRef}>\n          <button\n            type=\"button\"\n            className=\"topbar-account-button\"\n            onClick={() => setMenuContaAberto((prev) => !prev)}\n          >\n            <span className=\"topbar-avatar\">{iniciaisUtilizador}</span>\n            <span className=\"topbar-account-copy\">\n              <span className=\"topbar-account-name\">{nomeUtilizador}</span>\n              <small>{lojaAtual}</small>\n            </span>\n            <span className={`topbar-account-arrow ${menuContaAberto ? \"open\" : \"\"}`}>\n              \u25be\n            </span>\n          </button>\n\n          {menuContaAberto && (\n            <div className=\"topbar-account-menu\">\n              <div className=\"topbar-account-menu-header\">\n                <strong>{nomeUtilizador}</strong>\n                <span>{user?.email || lojaAtual}</span>\n              </div>\n\n              <button\n                type=\"button\"\n                className=\"topbar-account-menu-item\"\n                onClick={abrirModalPassword}\n              >\n                Alterar palavra-passe\n              </button>\n\n              <button\n                type=\"button\"\n                className=\"topbar-account-menu-item topbar-account-menu-item-danger\"\n                onClick={handleLogout}\n                disabled={loadingLogout}\n              >\n                {loadingLogout ? \"A sair...\" : \"Sair da conta\"}\n              </button>\n            </div>\n          )}\n        </div>\n      </div>\n\n      <div\n        className={`sidebar-overlay ${menuAberto ? \"show\" : \"\"}`}\n        onClick={fecharTudo}\n        aria-hidden={!menuAberto}\n      />\n\n      <aside\n        id=\"sidebar-navigation\"\n        className={`sidebar no-print ${menuAberto ? \"open\" : \"\"}`}\n        aria-hidden={!menuAberto}\n      >\n        <div className=\"sidebar-header\">\n          <PromoPilotMark tone=\"light\" />\n\n          <button\n            type=\"button\"\n            className=\"close-sidebar\"\n            onClick={fecharTudo}\n            aria-label=\"Fechar menu\"\n          >\n            \u00d7\n          </button>\n        </div>\n\n        <div className=\"sidebar-user-card\">\n          <span className=\"topbar-avatar sidebar-avatar\">{iniciaisUtilizador}</span>\n          <div>\n            <strong>{nomeUtilizador}</strong>\n            <span>{lojaAtual}</span>\n          </div>\n        </div>\n\n        <nav className=\"sidebar-body\" aria-label=\"Navega\u00e7\u00e3o principal\">\n          <div className=\"sidebar-section-label\">Cockpit</div>\n\n          <Link\n            to=\"/Homepage\"\n            className={`sidebar-link ${isActive(\"/Homepage\") ? \"active\" : \"\"}`}\n            onClick={fecharTudo}\n          >\n            <span className=\"sidebar-link-left\"><span className=\"sidebar-icon\">\u2318</span> In\u00edcio</span>\n            <small>Vis\u00e3o geral</small>\n          </Link>\n\n          <Link\n            to=\"/OrcamentosDossiers\"\n            className={`sidebar-link ${isActive(\"/OrcamentosDossiers\") ? \"active\" : \"\"}`}\n            onClick={fecharTudo}\n          >\n            <span className=\"sidebar-link-left\"><span className=\"sidebar-icon\">\u2197</span> Dossiers</span>\n            <small>Or\u00e7amentos</small>\n          </Link>\n\n          <div className=\"sidebar-section-label\">Produ\u00e7\u00e3o de loja</div>\n\n          <button\n            type=\"button\"\n            className={`sidebar-link ${rotaEtiquetasAtiva ? \"active\" : \"\"}`}\n            onClick={toggleSubmenu}\n            aria-expanded={submenuEtiquetasAberto}\n            aria-controls=\"submenu-etiquetas\"\n          >\n            <span className=\"sidebar-link-left\"><span className=\"sidebar-icon\">\ud83c\udff7</span> Etiquetas</span>\n            <span className={`arrow ${submenuEtiquetasAberto ? \"open\" : \"\"}`}>\u25b8</span>\n          </button>\n\n          {submenuEtiquetasAberto && (\n            <div id=\"submenu-etiquetas\" className=\"sidebar-submenu\">\n              <Link\n                to=\"/EtiquetasCampanha\"\n                className={`sidebar-sublink ${isActive(\"/EtiquetasCampanha\") ? \"active\" : \"\"}`}\n                onClick={fecharTudo}\n              >\n                Campanha manual\n              </Link>\n\n              <Link\n                to=\"/Etiquetas\"\n                className={`sidebar-sublink ${isActive(\"/Etiquetas\") ? \"active\" : \"\"}`}\n                onClick={fecharTudo}\n              >\n                Cat\u00e1logo e scan\n              </Link>\n\n              <Link\n                to=\"/EtiquetasCampanhaExcel\"\n                className={`sidebar-sublink ${isActive(\"/EtiquetasCampanhaExcel\") ? \"active\" : \"\"}`}\n                onClick={fecharTudo}\n              >\n                Importa\u00e7\u00e3o Excel\n              </Link>\n            </div>\n          )}\n        </nav>\n      </aside>\n\n      {modalPasswordAberto && (\n        <div className=\"force-password-overlay\">\n          <div\n            className=\"force-password-modal\"\n            role=\"dialog\"\n            aria-modal=\"true\"\n            aria-labelledby=\"change-password-title\"\n          >\n            <h2 id=\"change-password-title\">Alterar palavra-passe</h2>\n\n            <p>Defina uma nova palavra-passe para a sua conta.</p>\n\n            <form onSubmit={handleChangePassword} className=\"force-password-form\">\n              <label htmlFor=\"nova-password-topbar\">Nova palavra-passe</label>\n              <input\n                id=\"nova-password-topbar\"\n                type=\"password\"\n                value={novaPassword}\n                onChange={(e) => setNovaPassword(e.target.value)}\n                placeholder=\"Nova palavra-passe\"\n                autoComplete=\"new-password\"\n                required\n                disabled={loadingPassword}\n              />\n\n              <label htmlFor=\"confirmar-password-topbar\">\n                Confirmar palavra-passe\n              </label>\n              <input\n                id=\"confirmar-password-topbar\"\n                type=\"password\"\n                value={confirmarPassword}\n                onChange={(e) => setConfirmarPassword(e.target.value)}\n                placeholder=\"Confirmar palavra-passe\"\n                autoComplete=\"new-password\"\n                required\n                disabled={loadingPassword}\n              />\n\n              <div className=\"force-password-rules\">\n                M\u00ednimo 8 caracteres, com letras, n\u00fameros e pelo menos 1 car\u00e1cter especial.\n              </div>\n\n              {erroPassword && <p className=\"force-password-error\">{erroPassword}</p>}\n              {sucessoPassword && <p className=\"force-password-success\">{sucessoPassword}</p>}\n\n              <div className=\"popup-actions popup-actions-pro\">\n                <button type=\"submit\" className=\"btn btn-primary\" disabled={loadingPassword}>\n                  {loadingPassword ? \"A guardar...\" : \"Guardar\"}\n                </button>\n\n                <button\n                  type=\"button\"\n                  className=\"btn btn-secondary\"\n                  onClick={fecharModalPassword}\n                  disabled={loadingPassword}\n                >\n                  Cancelar\n                </button>\n              </div>\n            </form>\n          </div>\n        </div>\n      )}\n    </>\n  );\n}\n");
write("src/pages/Login.jsx", "import React, { useState } from \"react\";\nimport { Navigate } from \"react-router-dom\";\nimport ForcePasswordChangeModal from \"../components/ForcePasswordChangeModal\";\nimport PromoPilotMark from \"../components/brand/PromoPilotMark\";\nimport { useAuth } from \"../context/AuthContext\";\nimport { PROMOPILOT_BRAND, PROMOPILOT_MODULES } from \"../brand/promopilot\";\nimport \"../styles/styles.css\";\n\nexport default function Login() {\n  const {\n    user,\n    loadingAuth,\n    loadingProfile,\n    signIn,\n    onboardingRequired,\n    requiresPasswordChange,\n  } = useAuth();\n\n  const [email, setEmail] = useState(\"\");\n  const [senha, setSenha] = useState(\"\");\n  const [erro, setErro] = useState(\"\");\n  const [carregando, setCarregando] = useState(false);\n  const [mostrarSenha, setMostrarSenha] = useState(false);\n\n  const mostrarModalOnboarding = !!user && !loadingProfile && onboardingRequired;\n\n  if (loadingAuth || (user && loadingProfile)) {\n    return (\n      <div className=\"login-page pp-login-page\">\n        <div className=\"pp-login-loading\">\n          <PromoPilotMark tone=\"light\" />\n          <p>A verificar sess\u00e3o...</p>\n        </div>\n      </div>\n    );\n  }\n\n  if (user && !onboardingRequired) {\n    return <Navigate to=\"/Homepage\" replace />;\n  }\n\n  async function handleSubmit(e) {\n    e.preventDefault();\n    setErro(\"\");\n    setCarregando(true);\n\n    try {\n      const emailLimpo = String(email || \"\").trim();\n      await signIn(emailLimpo, senha);\n    } catch (_err) {\n      setErro(\"Email ou palavra-passe inv\u00e1lidos.\");\n    } finally {\n      setCarregando(false);\n    }\n  }\n\n  return (\n    <div className=\"login-page pp-login-page\">\n      <div className=\"pp-login-bg-grid\" aria-hidden=\"true\" />\n      <div className=\"pp-login-orb pp-login-orb-one\" aria-hidden=\"true\" />\n      <div className=\"pp-login-orb pp-login-orb-two\" aria-hidden=\"true\" />\n\n      <main className=\"pp-login-layout\">\n        <section className=\"pp-login-intro\" aria-label=\"Apresenta\u00e7\u00e3o PromoPilot\">\n          <PromoPilotMark tone=\"light\" className=\"pp-login-brand\" />\n\n          <div className=\"pp-login-hero-copy\">\n            <span className=\"pp-kicker\">Retail execution platform</span>\n            <h1>{PROMOPILOT_BRAND.claim}</h1>\n            <p>\n              Uma experi\u00eancia mais clara para loja: pesquisa artigos, prepara campanhas,\n              gera etiquetas e cria dossiers de or\u00e7amento sem perder contexto.\n            </p>\n          </div>\n\n          <div className=\"pp-login-module-grid\">\n            {PROMOPILOT_MODULES.map((module) => (\n              <article key={module.key} className=\"pp-login-module-card\">\n                <strong>{module.label}</strong>\n                <span>{module.description}</span>\n              </article>\n            ))}\n          </div>\n\n          <div className=\"pp-login-trust-row\">\n            <span>Opera\u00e7\u00e3o em loja</span>\n            <span>Cat\u00e1logo Supabase</span>\n            <span>Dossiers comerciais</span>\n          </div>\n        </section>\n\n        <section className=\"login-card pp-login-card\" aria-label=\"Autentica\u00e7\u00e3o\">\n          {!user && (\n            <>\n              <div className=\"pp-login-card-header\">\n                <span className=\"pp-card-chip\">{PROMOPILOT_BRAND.company}</span>\n                <h2>Entrar no PromoPilot</h2>\n                <p>Acesso reservado \u00e0s equipas autorizadas.</p>\n              </div>\n\n              <form onSubmit={handleSubmit} className=\"login-form pp-login-form\">\n                <label htmlFor=\"email\">Email profissional</label>\n                <input\n                  id=\"email\"\n                  type=\"email\"\n                  placeholder=\"seu.email@susiarte.com\"\n                  value={email}\n                  onChange={(e) => setEmail(e.target.value)}\n                  autoComplete=\"email\"\n                  disabled={carregando}\n                  required\n                />\n\n                <label htmlFor=\"senha\">Palavra-passe</label>\n                <div className=\"login-password-wrap\">\n                  <input\n                    id=\"senha\"\n                    type={mostrarSenha ? \"text\" : \"password\"}\n                    placeholder=\"A sua palavra-passe\"\n                    value={senha}\n                    onChange={(e) => setSenha(e.target.value)}\n                    autoComplete=\"current-password\"\n                    disabled={carregando}\n                    required\n                  />\n                  <button\n                    type=\"button\"\n                    className=\"login-password-toggle\"\n                    onClick={() => setMostrarSenha((prev) => !prev)}\n                    aria-label={mostrarSenha ? \"Ocultar palavra-passe\" : \"Mostrar palavra-passe\"}\n                    aria-pressed={mostrarSenha}\n                    disabled={carregando}\n                  >\n                    {mostrarSenha ? \"Ocultar\" : \"Mostrar\"}\n                  </button>\n                </div>\n\n                <button type=\"submit\" className=\"login-submit pp-login-submit\" disabled={carregando}>\n                  <span>{carregando ? \"A entrar...\" : \"Entrar no cockpit\"}</span>\n                </button>\n\n                {erro && <p className=\"login-erro\">{erro}</p>}\n              </form>\n\n              <div className=\"pp-login-footer-note\">\n                <strong>Modo produ\u00e7\u00e3o</strong>\n                <span>Confirma sempre pre\u00e7os e artigos antes de imprimir ou enviar ao cliente.</span>\n              </div>\n            </>\n          )}\n        </section>\n      </main>\n\n      {mostrarModalOnboarding && (\n        <ForcePasswordChangeModal\n          open={true}\n          requirePassword={requiresPasswordChange}\n        />\n      )}\n    </div>\n  );\n}\n");
write("src/components/home/HomeHero.jsx", "import React from \"react\";\nimport { PROMOPILOT_BRAND } from \"../../brand/promopilot\";\n\nexport default function HomeHero({\n  pesquisa,\n  onPesquisaChange,\n  onPesquisaFocus,\n  onKeyDown,\n  loading,\n  erro,\n  sugestoes,\n  highlightedIndex,\n  onSuggestionHover,\n  onSuggestionClick,\n}) {\n  return (\n    <section className=\"home-hero pp-home-hero\">\n      <div className=\"pp-home-hero-copy\">\n        <span className=\"pp-kicker\">Cockpit operacional</span>\n        <h1 className=\"page-title\">Bem-vindo ao {PROMOPILOT_BRAND.appName}</h1>\n        <p className=\"page-subtitle\">\n          Uma entrada \u00fanica para campanhas, etiquetas, cat\u00e1logo de artigos e dossiers de or\u00e7amento.\n          Mais r\u00e1pido para a loja, mais consistente para o cliente.\n        </p>\n\n        <div className=\"pp-hero-metrics\" aria-label=\"\u00c1reas principais\">\n          <span><strong>Campanhas</strong> etiquetas manuais e Excel</span>\n          <span><strong>Cat\u00e1logo</strong> pesquisa por artigo, EAN e modelo</span>\n          <span><strong>Dossiers</strong> propostas comerciais em PDF</span>\n        </div>\n      </div>\n\n      <div className=\"pp-home-command-card\">\n        <div className=\"pp-command-header\">\n          <span>Comando r\u00e1pido</span>\n          {loading && <small>A preparar pesquisa...</small>}\n        </div>\n\n        {erro && <p className=\"ai-error\">{erro}</p>}\n\n        <div className=\"home-search-wrap pp-search-wrap\">\n          <input\n            id=\"home-search-input\"\n            type=\"text\"\n            value={pesquisa}\n            onChange={(e) => onPesquisaChange(e.target.value)}\n            onFocus={onPesquisaFocus}\n            onKeyDown={onKeyDown}\n            placeholder=\"Pesquisar artigo, EAN, descri\u00e7\u00e3o, marca ou modelo\"\n            className=\"home-search-input pp-command-input\"\n            autoComplete=\"off\"\n            aria-label=\"Pesquisar artigos\"\n            aria-autocomplete=\"list\"\n            aria-controls=\"home-search-suggestions\"\n            aria-activedescendant={highlightedIndex >= 0 ? `home-suggestion-${highlightedIndex}` : undefined}\n          />\n        </div>\n\n        <p className=\"pp-command-hint\">Enter abre a pesquisa no cat\u00e1logo. Use scan para leitura direta em loja.</p>\n\n        {sugestoes.length > 0 && (\n          <div id=\"home-search-suggestions\" className=\"home-search-suggestions pp-search-suggestions\" role=\"listbox\">\n            {sugestoes.map((item, index) => (\n              <button\n                key={`${item.artigo}-${index}`}\n                id={`home-suggestion-${index}`}\n                type=\"button\"\n                role=\"option\"\n                aria-selected={highlightedIndex === index}\n                className={`home-suggestion-item ${highlightedIndex === index ? \"is-active\" : \"\"}`}\n                onMouseEnter={() => onSuggestionHover(index)}\n                onClick={() => onSuggestionClick(item)}\n              >\n                <strong>{item.artigo}</strong>\n                <span>{item.descricao}</span>\n                {item.codigoBarras && <small>EAN: {item.codigoBarras}</small>}\n              </button>\n            ))}\n          </div>\n        )}\n      </div>\n    </section>\n  );\n}\n");
write("src/components/home/HomeQuickActions.jsx", "import React from \"react\";\n\nconst ACTIONS = [\n  {\n    key: \"campaign\",\n    title: \"Criar campanha\",\n    subtitle: \"Montar etiquetas de campanha com PVP3 antes e PVP2 atual.\",\n    icon: \"\ud83c\udff7\",\n    tone: \"primary\",\n    action: \"onOpenCampaign\",\n  },\n  {\n    key: \"articles\",\n    title: \"Cat\u00e1logo de artigos\",\n    subtitle: \"Pesquisar, confirmar pre\u00e7os, EAN e descri\u00e7\u00f5es.\",\n    icon: \"\ud83d\udce6\",\n    tone: \"blue\",\n    action: \"onOpenArticles\",\n  },\n  {\n    key: \"scan\",\n    title: \"Scan em loja\",\n    subtitle: \"Ler c\u00f3digos de barras e encontrar artigos rapidamente.\",\n    icon: \"\u25a3\",\n    tone: \"green\",\n    action: \"onOpenScan\",\n  },\n  {\n    key: \"dossiers\",\n    title: \"Dossiers de or\u00e7amento\",\n    subtitle: \"Transformar ORCs em PDFs comerciais com imagem e resumo.\",\n    icon: \"\u2197\",\n    tone: \"violet\",\n    action: \"onOpenDossiers\",\n  },\n  {\n    key: \"excel\",\n    title: \"Importa\u00e7\u00e3o Excel\",\n    subtitle: \"Produ\u00e7\u00e3o em lote para campanhas preparadas externamente.\",\n    icon: \"\ud83d\udcca\",\n    tone: \"slate\",\n    action: \"onOpenExcel\",\n  },\n];\n\nexport default function HomeQuickActions({\n  onOpenCampaign,\n  onOpenArticles,\n  onOpenScan,\n  onOpenExcel,\n  onOpenDossiers,\n}) {\n  const handlers = {\n    onOpenCampaign,\n    onOpenArticles,\n    onOpenScan,\n    onOpenExcel,\n    onOpenDossiers,\n  };\n\n  return (\n    <section className=\"pp-quick-section\" aria-label=\"A\u00e7\u00f5es r\u00e1pidas\">\n      <div className=\"pp-section-heading\">\n        <span className=\"pp-kicker\">A\u00e7\u00f5es r\u00e1pidas</span>\n        <h2>O que queres fazer agora?</h2>\n      </div>\n\n      <div className=\"home-grid pp-action-grid\">\n        {ACTIONS.map((item) => {\n          const handler = handlers[item.action];\n\n          return (\n            <button\n              key={item.key}\n              type=\"button\"\n              className={`home-card pp-action-card pp-action-${item.tone}`}\n              onClick={handler}\n              disabled={!handler}\n            >\n              <span className=\"home-card-icon pp-action-icon\">{item.icon}</span>\n              <span className=\"home-card-text pp-action-copy\">\n                <strong>{item.title}</strong>\n                <small>{item.subtitle}</small>\n              </span>\n              <span className=\"pp-action-arrow\" aria-hidden=\"true\">\u2192</span>\n            </button>\n          );\n        })}\n      </div>\n    </section>\n  );\n}\n");
write("src/components/home/HomeSummarySection.jsx", "import React from \"react\";\n\nfunction formatNumber(value) {\n  const number = Number(value || 0);\n\n  if (!Number.isFinite(number)) return value || 0;\n\n  return new Intl.NumberFormat(\"pt-PT\").format(number);\n}\n\nexport default function HomeSummarySection({ totalArtigos, totalCampanhas }) {\n  const cards = [\n    {\n      label: \"Artigos em cat\u00e1logo\",\n      value: formatNumber(totalArtigos),\n      note: \"Base operacional sincronizada\",\n    },\n    {\n      label: \"Campanhas recentes\",\n      value: formatNumber(totalCampanhas),\n      note: \"Manuais e autom\u00e1ticas\",\n    },\n    {\n      label: \"Fluxo recomendado\",\n      value: \"Pesquisar \u2192 Criar \u2192 Imprimir\",\n      note: \"Menos passos, menos erro\",\n    },\n  ];\n\n  return (\n    <section className=\"home-section pp-summary-section\">\n      <div className=\"table-card-header pp-card-header\">\n        <div>\n          <span className=\"pp-kicker\">Sa\u00fade operacional</span>\n          <h2>Resumo do cockpit</h2>\n        </div>\n      </div>\n\n      <div className=\"resumo-cards pp-summary-grid\">\n        {cards.map((card) => (\n          <article key={card.label} className=\"resumo-card pp-summary-card\">\n            <span className=\"resumo-label\">{card.label}</span>\n            <strong>{card.value}</strong>\n            <small>{card.note}</small>\n          </article>\n        ))}\n      </div>\n    </section>\n  );\n}\n");
write("src/components/home/HomeHistorySection.jsx", "import React from \"react\";\n\nexport default function HomeHistorySection({\n  historicoPreview,\n  onOpenCampaign,\n  formatarDataHistorico,\n  formatarAutorCampanha,\n}) {\n  return (\n    <section className=\"home-section pp-history-section\">\n      <div className=\"table-card-header pp-card-header\">\n        <div>\n          <span className=\"pp-kicker\">\u00daltimas execu\u00e7\u00f5es</span>\n          <h2>Campanhas manuais</h2>\n        </div>\n      </div>\n\n      <div className=\"home-history-wrap\">\n        {historicoPreview.length === 0 ? (\n          <div className=\"home-history-empty pp-empty-state\">\n            Ainda n\u00e3o existem campanhas guardadas.\n          </div>\n        ) : (\n          <div className=\"home-history-grid pp-history-grid\">\n            {historicoPreview\n              .filter((campanha) => campanha && campanha.id)\n              .map((campanha) => (\n                <button\n                  key={campanha.id}\n                  type=\"button\"\n                  className=\"home-history-card pp-history-card\"\n                  onClick={() => onOpenCampaign(campanha)}\n                >\n                  <div className=\"home-history-top\">\n                    <div>\n                      <strong>{campanha.titulo || \"Campanha manual\"}</strong>\n                      <span>{formatarDataHistorico(campanha.criadoEm)}</span>\n                    </div>\n                    <span className=\"home-history-format\">\n                      {String(campanha.formatoEtiqueta || \"a6\").toUpperCase()}\n                    </span>\n                  </div>\n\n                  <div className=\"home-history-meta\">\n                    <span>{campanha.totalArtigos || 0} artigos</span>\n                    <span>Validade: {campanha.anoValidade || \"-\"}</span>\n                    <span>{formatarAutorCampanha(campanha)}</span>\n                  </div>\n\n                  <div className=\"home-history-preview\">\n                    {Array.isArray(campanha.dados) &&\n                      campanha.dados.slice(0, 2).map((item) => (\n                        <p key={item.id || `${campanha.id}-${item.codigo}`}>\n                          {item.codigo} \u2014 {item.descricao}\n                        </p>\n                      ))}\n                  </div>\n                </button>\n              ))}\n          </div>\n        )}\n      </div>\n    </section>\n  );\n}\n");
write("src/components/home/HomeAutomaticCampaignHistorySection.jsx", "import React from \"react\";\n\nfunction getStatusLabel(status) {\n  const value = String(status || \"processed\").toLowerCase();\n\n  if (value === \"sent\") return \"Enviado\";\n  if (value === \"error\" || value === \"failed\") return \"Com erro\";\n  if (value === \"pending\") return \"Pendente\";\n  if (value === \"processing\") return \"A processar\";\n  return \"Processado\";\n}\n\nfunction getPdfUrl(campanha) {\n  return campanha?.pdfUrl || campanha?.pdfs?.[campanha?.store] || \"\";\n}\n\nfunction countFormats(items = []) {\n  return (Array.isArray(items) ? items : []).reduce(\n    (acc, item) => {\n      const format = String(item?._formato || item?.formato_final || item?.formatoEtiqueta || \"a6\").toLowerCase();\n      if (format === \"a5\") acc.a5 += 1;\n      else acc.a6 += 1;\n      return acc;\n    },\n    { a5: 0, a6: 0 },\n  );\n}\n\nexport default function HomeAutomaticCampaignHistorySection({\n  historicoPreview,\n  onOpenCampaign,\n  formatarDataHistorico,\n}) {\n  return (\n    <section className=\"home-section pp-history-section\">\n      <div className=\"table-card-header pp-card-header\">\n        <div>\n          <span className=\"pp-kicker\">Automa\u00e7\u00e3o</span>\n          <h2>Campanhas autom\u00e1ticas</h2>\n        </div>\n      </div>\n\n      <div className=\"home-history-wrap\">\n        {historicoPreview.length === 0 ? (\n          <div className=\"home-history-empty pp-empty-state\">\n            Ainda n\u00e3o existem campanhas autom\u00e1ticas guardadas.\n          </div>\n        ) : (\n          <div className=\"home-history-grid pp-history-grid\">\n            {historicoPreview\n              .filter((campanha) => campanha && campanha.id)\n              .map((campanha) => {\n                const pdfUrl = getPdfUrl(campanha);\n                const formatCounts = countFormats(campanha.dados);\n\n                return (\n                  <button\n                    key={campanha.id}\n                    type=\"button\"\n                    className=\"home-history-card home-history-card-auto pp-history-card pp-history-card-auto\"\n                    onClick={() => onOpenCampaign(campanha)}\n                  >\n                    <div className=\"home-history-top\">\n                      <div>\n                        <strong>{campanha.titulo || \"Campanha autom\u00e1tica\"}</strong>\n                        <span>{formatarDataHistorico(campanha.criadoEm)}</span>\n                      </div>\n\n                      <span className=\"home-history-format home-history-format-auto\">\n                        AUTO\n                      </span>\n                    </div>\n\n                    <div className=\"home-history-meta\">\n                      <span>{campanha.totalArtigos || 0} artigos</span>\n                      <span>{campanha.store || \"Loja\"}</span>\n                      <span>{getStatusLabel(campanha.status)}</span>\n                      <span>A5: {formatCounts.a5} \u00b7 A6: {formatCounts.a6}</span>\n                      {pdfUrl ? <span>PDF dispon\u00edvel</span> : null}\n                    </div>\n\n                    <div className=\"home-history-preview\">\n                      {campanha.emailSubject ? <p>Email: {campanha.emailSubject}</p> : null}\n                      {campanha.emailFrom ? <p>De: {campanha.emailFrom}</p> : null}\n                      {Array.isArray(campanha.dados) &&\n                        campanha.dados.slice(0, 2).map((item) => (\n                          <p key={item.id || `${campanha.id}-${item.codigo || item.artigo}`}>\n                            {item.codigo || item.artigo || \"-\"} \u2014 {item.descricao || \"-\"}\n                          </p>\n                        ))}\n                    </div>\n                  </button>\n                );\n              })}\n          </div>\n        )}\n      </div>\n    </section>\n  );\n}\n");
write("src/styles/promopilot.css", "/* =========================================================\n   PROMOPILOT PRODUCT UI V2\n   Visual polish layer loaded after the legacy styles.\n   ========================================================= */\n:root {\n  --pp-bg: #0b1120;\n  --pp-bg-soft: #111827;\n  --pp-surface: rgba(255, 255, 255, 0.96);\n  --pp-surface-strong: #ffffff;\n  --pp-surface-muted: #f6f8fb;\n  --pp-ink: #0f172a;\n  --pp-ink-muted: #5b6475;\n  --pp-ink-soft: #8a94a6;\n  --pp-line: rgba(148, 163, 184, 0.24);\n  --pp-line-strong: rgba(15, 23, 42, 0.1);\n  --pp-orange: #f97316;\n  --pp-orange-dark: #ea580c;\n  --pp-orange-soft: #fff3ea;\n  --pp-blue: #2563eb;\n  --pp-blue-soft: #eff6ff;\n  --pp-green: #059669;\n  --pp-violet: #7c3aed;\n  --pp-radius: 22px;\n  --pp-radius-lg: 30px;\n  --pp-shadow: 0 22px 70px rgba(15, 23, 42, 0.12);\n  --pp-shadow-soft: 0 12px 35px rgba(15, 23, 42, 0.08);\n\n  --color-primary: var(--pp-orange);\n  --color-primary-dark: var(--pp-orange-dark);\n  --color-primary-action: var(--pp-blue);\n  --color-primary-action-dark: #1d4ed8;\n  --color-bg: #f4f7fb;\n  --color-surface: #ffffff;\n  --color-border: #e6eaf1;\n  --shadow-card: var(--pp-shadow-soft);\n}\n\nbody {\n  background:\n    radial-gradient(circle at top left, rgba(249, 115, 22, 0.08), transparent 28vw),\n    radial-gradient(circle at top right, rgba(37, 99, 235, 0.08), transparent 30vw),\n    #f4f7fb;\n}\n\nbutton,\na {\n  -webkit-tap-highlight-color: transparent;\n}\n\nbutton:disabled {\n  opacity: 0.62;\n  cursor: not-allowed;\n}\n\n/* Brand */\n.pp-brand-lockup {\n  display: inline-flex;\n  align-items: center;\n  gap: 12px;\n  min-width: 0;\n}\n\n.pp-brand-mark {\n  position: relative;\n  width: 44px;\n  height: 44px;\n  border-radius: 15px;\n  background:\n    linear-gradient(135deg, rgba(249, 115, 22, 0.96), rgba(234, 88, 12, 0.96)),\n    var(--pp-orange);\n  color: #fff;\n  display: grid;\n  place-items: center;\n  box-shadow: 0 16px 32px rgba(249, 115, 22, 0.28);\n  overflow: hidden;\n  flex: 0 0 auto;\n}\n\n.pp-brand-mark::before {\n  content: \"\";\n  position: absolute;\n  inset: -40% -10% auto auto;\n  width: 52px;\n  height: 52px;\n  border-radius: 999px;\n  background: rgba(255, 255, 255, 0.22);\n}\n\n.pp-brand-mark strong {\n  position: relative;\n  font-size: 15px;\n  font-weight: 900;\n  letter-spacing: -0.04em;\n}\n\n.pp-brand-mark-dot {\n  position: absolute;\n  right: 8px;\n  bottom: 8px;\n  width: 7px;\n  height: 7px;\n  border-radius: 999px;\n  background: #bfdbfe;\n  box-shadow: 0 0 0 4px rgba(191, 219, 254, 0.14);\n}\n\n.pp-brand-copy {\n  display: flex;\n  flex-direction: column;\n  gap: 1px;\n  min-width: 0;\n}\n\n.pp-brand-name {\n  font-size: 19px;\n  line-height: 1;\n  font-weight: 900;\n  letter-spacing: -0.04em;\n}\n\n.pp-brand-descriptor {\n  font-size: 11px;\n  font-weight: 800;\n  letter-spacing: 0.12em;\n  text-transform: uppercase;\n  color: var(--pp-ink-soft);\n}\n\n.pp-brand-lockup-light .pp-brand-name,\n.pp-brand-lockup-light .pp-brand-descriptor {\n  color: #fff;\n}\n\n.pp-brand-lockup-light .pp-brand-descriptor {\n  opacity: 0.68;\n}\n\n.pp-brand-compact .pp-brand-mark {\n  width: 40px;\n  height: 40px;\n}\n\n/* Splash */\n.pp-splash-screen {\n  min-height: 100vh;\n  display: grid;\n  place-items: center;\n  background:\n    radial-gradient(circle at 18% 20%, rgba(249, 115, 22, 0.35), transparent 34%),\n    radial-gradient(circle at 82% 16%, rgba(37, 99, 235, 0.28), transparent 30%),\n    linear-gradient(135deg, #0b1120 0%, #111827 48%, #1f2937 100%);\n  color: #fff;\n}\n\n.pp-splash-card {\n  width: min(420px, calc(100vw - 40px));\n  padding: 34px;\n  border-radius: 32px;\n  background: rgba(255, 255, 255, 0.08);\n  border: 1px solid rgba(255, 255, 255, 0.13);\n  box-shadow: 0 28px 80px rgba(0, 0, 0, 0.32);\n  backdrop-filter: blur(18px);\n  display: grid;\n  gap: 20px;\n}\n\n.pp-splash-card p {\n  margin: 0;\n  color: rgba(255, 255, 255, 0.76);\n  font-weight: 700;\n}\n\n.pp-splash-loader {\n  height: 7px;\n  border-radius: 999px;\n  overflow: hidden;\n  background: rgba(255, 255, 255, 0.14);\n}\n\n.pp-splash-loader span {\n  display: block;\n  width: 42%;\n  height: 100%;\n  border-radius: inherit;\n  background: linear-gradient(90deg, var(--pp-orange), #93c5fd);\n  animation: ppLoader 1.1s ease-in-out infinite;\n}\n\n@keyframes ppLoader {\n  0% { transform: translateX(-105%); }\n  100% { transform: translateX(250%); }\n}\n\n/* Topbar + sidebar */\n.topbar-site {\n  height: 76px;\n  background:\n    linear-gradient(135deg, rgba(15, 23, 42, 0.98), rgba(17, 24, 39, 0.96)),\n    #0f172a;\n  border-bottom: 1px solid rgba(255, 255, 255, 0.08);\n  box-shadow: 0 20px 48px rgba(15, 23, 42, 0.18);\n  padding: 0 22px;\n  gap: 16px;\n}\n\n.menu-button {\n  width: 44px;\n  height: 44px;\n  border-radius: 15px;\n  background: rgba(255, 255, 255, 0.08);\n  border: 1px solid rgba(255, 255, 255, 0.1);\n  display: grid;\n  place-items: center;\n  gap: 4px;\n  padding: 10px;\n}\n\n.menu-button span {\n  display: block;\n  width: 18px;\n  height: 2px;\n  border-radius: 999px;\n  background: #fff;\n}\n\n.pp-topbar-brand {\n  flex: 0 0 auto;\n}\n\n.topbar-title {\n  display: none;\n}\n\n.topbar-context {\n  display: flex;\n  flex-direction: column;\n  gap: 2px;\n  padding: 8px 14px;\n  border-radius: 16px;\n  background: rgba(255, 255, 255, 0.07);\n  color: #fff;\n}\n\n.topbar-context-label {\n  font-size: 10px;\n  font-weight: 900;\n  letter-spacing: 0.14em;\n  text-transform: uppercase;\n  opacity: 0.56;\n}\n\n.topbar-context strong {\n  font-size: 13px;\n}\n\n.topbar-account-button {\n  gap: 10px;\n  padding: 8px 10px 8px 8px;\n  border-radius: 18px;\n  background: rgba(255, 255, 255, 0.08);\n}\n\n.topbar-avatar {\n  width: 38px;\n  height: 38px;\n  border-radius: 14px;\n  background: linear-gradient(135deg, var(--pp-blue), #60a5fa);\n  color: #fff;\n  display: grid;\n  place-items: center;\n  font-size: 13px;\n  font-weight: 900;\n  flex: 0 0 auto;\n}\n\n.topbar-account-copy {\n  display: flex;\n  flex-direction: column;\n  min-width: 0;\n  text-align: left;\n}\n\n.topbar-account-name {\n  max-width: 180px;\n  line-height: 1.15;\n}\n\n.topbar-account-copy small {\n  color: rgba(255, 255, 255, 0.6);\n  font-weight: 700;\n  max-width: 180px;\n  overflow: hidden;\n  text-overflow: ellipsis;\n  white-space: nowrap;\n}\n\n.topbar-account-menu {\n  border: 1px solid rgba(15, 23, 42, 0.08);\n  border-radius: 18px;\n  box-shadow: var(--pp-shadow);\n  overflow: hidden;\n}\n\n.topbar-account-menu-header {\n  padding: 14px 16px;\n  border-bottom: 1px solid #edf1f7;\n  display: grid;\n  gap: 3px;\n}\n\n.topbar-account-menu-header strong {\n  color: var(--pp-ink);\n}\n\n.topbar-account-menu-header span {\n  color: var(--pp-ink-muted);\n  font-size: 12px;\n  overflow: hidden;\n  text-overflow: ellipsis;\n}\n\n.sidebar {\n  width: 330px;\n  background: #0b1120;\n  color: #fff;\n  box-shadow: 18px 0 80px rgba(0, 0, 0, 0.35);\n}\n\n.sidebar-header {\n  height: 92px;\n  background:\n    radial-gradient(circle at 20% 0%, rgba(249, 115, 22, 0.45), transparent 40%),\n    #0b1120;\n  padding: 18px 18px 14px;\n  border-bottom: 1px solid rgba(255, 255, 255, 0.08);\n}\n\n.close-sidebar {\n  width: 38px;\n  height: 38px;\n  border-radius: 14px;\n  background: rgba(255, 255, 255, 0.08);\n  font-size: 28px;\n}\n\n.sidebar-user-card {\n  margin: 18px;\n  padding: 14px;\n  border-radius: 20px;\n  background: rgba(255, 255, 255, 0.07);\n  border: 1px solid rgba(255, 255, 255, 0.09);\n  display: flex;\n  gap: 12px;\n  align-items: center;\n}\n\n.sidebar-user-card strong {\n  display: block;\n  color: #fff;\n  line-height: 1.2;\n}\n\n.sidebar-user-card span:last-child {\n  color: rgba(255, 255, 255, 0.58);\n  font-size: 12px;\n  font-weight: 700;\n}\n\n.sidebar-avatar {\n  width: 42px;\n  height: 42px;\n}\n\n.sidebar-body {\n  padding: 0 18px 24px;\n  gap: 9px;\n}\n\n.sidebar-section-label {\n  margin: 14px 4px 4px;\n  color: rgba(255, 255, 255, 0.44);\n  font-size: 11px;\n  font-weight: 900;\n  letter-spacing: 0.14em;\n  text-transform: uppercase;\n}\n\n.sidebar-link {\n  border: 1px solid rgba(255, 255, 255, 0.08);\n  background: rgba(255, 255, 255, 0.055);\n  color: rgba(255, 255, 255, 0.86);\n  border-radius: 17px;\n  min-height: 52px;\n}\n\n.sidebar-link:hover {\n  background: rgba(255, 255, 255, 0.09);\n}\n\n.sidebar-link.active {\n  color: #fff;\n  background:\n    linear-gradient(135deg, rgba(249, 115, 22, 0.22), rgba(37, 99, 235, 0.12)),\n    rgba(255, 255, 255, 0.08);\n  border-color: rgba(249, 115, 22, 0.38);\n}\n\n.sidebar-link-left {\n  display: inline-flex;\n  align-items: center;\n  gap: 11px;\n}\n\n.sidebar-icon {\n  width: 28px;\n  height: 28px;\n  display: grid;\n  place-items: center;\n  border-radius: 11px;\n  background: rgba(255, 255, 255, 0.08);\n}\n\n.sidebar-link small {\n  color: rgba(255, 255, 255, 0.46);\n  font-size: 11px;\n}\n\n.sidebar-submenu {\n  margin-left: 16px;\n  padding-left: 14px;\n  border-left: 1px solid rgba(255, 255, 255, 0.11);\n}\n\n.sidebar-sublink {\n  color: rgba(255, 255, 255, 0.72);\n  background: rgba(255, 255, 255, 0.045);\n  border-color: rgba(255, 255, 255, 0.07);\n}\n\n.sidebar-sublink:hover,\n.sidebar-sublink.active {\n  background: rgba(249, 115, 22, 0.16);\n  border-color: rgba(249, 115, 22, 0.28);\n  color: #fff;\n}\n\n.sidebar-overlay.show {\n  background: rgba(2, 6, 23, 0.66);\n  backdrop-filter: blur(4px);\n}\n\n/* Login */\n.pp-login-page {\n  position: fixed;\n  inset: 0;\n  min-height: 100vh;\n  overflow: auto;\n  background:\n    radial-gradient(circle at 20% 18%, rgba(249, 115, 22, 0.34), transparent 28%),\n    radial-gradient(circle at 78% 8%, rgba(37, 99, 235, 0.34), transparent 30%),\n    linear-gradient(135deg, #0b1120 0%, #111827 46%, #172033 100%);\n  color: #fff;\n}\n\n.pp-login-bg-grid {\n  position: fixed;\n  inset: 0;\n  opacity: 0.22;\n  background-image:\n    linear-gradient(rgba(255, 255, 255, 0.07) 1px, transparent 1px),\n    linear-gradient(90deg, rgba(255, 255, 255, 0.07) 1px, transparent 1px);\n  background-size: 44px 44px;\n  mask-image: linear-gradient(to bottom, #000 0%, transparent 75%);\n}\n\n.pp-login-orb {\n  position: fixed;\n  border-radius: 999px;\n  filter: blur(4px);\n  opacity: 0.72;\n}\n\n.pp-login-orb-one {\n  left: -80px;\n  bottom: 12%;\n  width: 220px;\n  height: 220px;\n  background: rgba(249, 115, 22, 0.22);\n}\n\n.pp-login-orb-two {\n  right: -110px;\n  top: 18%;\n  width: 280px;\n  height: 280px;\n  background: rgba(37, 99, 235, 0.20);\n}\n\n.pp-login-layout {\n  position: relative;\n  z-index: 1;\n  width: min(1180px, calc(100vw - 40px));\n  min-height: 100vh;\n  margin: 0 auto;\n  display: grid;\n  grid-template-columns: minmax(0, 1.1fr) 440px;\n  gap: 42px;\n  align-items: center;\n  padding: 52px 0;\n}\n\n.pp-login-intro {\n  display: grid;\n  gap: 30px;\n}\n\n.pp-login-hero-copy {\n  max-width: 680px;\n}\n\n.pp-kicker {\n  display: inline-flex;\n  align-items: center;\n  gap: 8px;\n  color: var(--pp-orange);\n  font-size: 11px;\n  font-weight: 900;\n  letter-spacing: 0.16em;\n  text-transform: uppercase;\n}\n\n.pp-kicker::before {\n  content: \"\";\n  width: 8px;\n  height: 8px;\n  border-radius: 999px;\n  background: currentColor;\n  box-shadow: 0 0 0 5px rgba(249, 115, 22, 0.12);\n}\n\n.pp-login-hero-copy h1 {\n  margin: 14px 0 16px;\n  font-size: clamp(42px, 5vw, 74px);\n  line-height: 0.94;\n  letter-spacing: -0.07em;\n}\n\n.pp-login-hero-copy p {\n  margin: 0;\n  color: rgba(255, 255, 255, 0.72);\n  max-width: 610px;\n  font-size: 17px;\n  line-height: 1.7;\n}\n\n.pp-login-module-grid {\n  display: grid;\n  grid-template-columns: repeat(2, minmax(0, 1fr));\n  gap: 14px;\n  max-width: 760px;\n}\n\n.pp-login-module-card {\n  padding: 18px;\n  border-radius: 22px;\n  background: rgba(255, 255, 255, 0.075);\n  border: 1px solid rgba(255, 255, 255, 0.11);\n  backdrop-filter: blur(10px);\n}\n\n.pp-login-module-card strong {\n  display: block;\n  margin-bottom: 8px;\n  color: #fff;\n}\n\n.pp-login-module-card span {\n  color: rgba(255, 255, 255, 0.66);\n  line-height: 1.5;\n  font-size: 13px;\n}\n\n.pp-login-trust-row {\n  display: flex;\n  flex-wrap: wrap;\n  gap: 10px;\n}\n\n.pp-login-trust-row span,\n.pp-card-chip {\n  display: inline-flex;\n  align-items: center;\n  padding: 8px 11px;\n  border-radius: 999px;\n  background: rgba(255, 255, 255, 0.09);\n  color: rgba(255, 255, 255, 0.78);\n  font-size: 12px;\n  font-weight: 800;\n}\n\n.pp-login-card {\n  position: relative;\n  width: 100%;\n  max-height: none;\n  overflow: visible;\n  padding: 30px;\n  border-radius: 32px;\n  background: rgba(255, 255, 255, 0.97);\n  border: 1px solid rgba(255, 255, 255, 0.65);\n  box-shadow: 0 32px 90px rgba(0, 0, 0, 0.35);\n  animation: none;\n}\n\n.pp-login-card-header h2 {\n  margin: 16px 0 8px;\n  color: var(--pp-ink);\n  font-size: 31px;\n  line-height: 1.05;\n  letter-spacing: -0.04em;\n}\n\n.pp-login-card-header p {\n  margin: 0 0 22px;\n  color: var(--pp-ink-muted);\n  line-height: 1.5;\n}\n\n.pp-card-chip {\n  background: var(--pp-orange-soft);\n  color: var(--pp-orange-dark);\n}\n\n.pp-login-form label {\n  color: var(--pp-ink);\n}\n\n.pp-login-form input {\n  background: #f8fafc;\n  border: 1px solid #dbe3ef;\n  color: var(--pp-ink);\n  box-shadow: none;\n}\n\n.pp-login-form input:focus {\n  border-color: var(--pp-blue);\n  box-shadow: 0 0 0 4px rgba(37, 99, 235, 0.11);\n  transform: none;\n}\n\n.pp-login-form input::placeholder {\n  color: #94a3b8;\n}\n\n.pp-login-submit {\n  margin-top: 20px;\n  background: linear-gradient(135deg, var(--pp-orange), var(--pp-orange-dark));\n  box-shadow: 0 16px 34px rgba(249, 115, 22, 0.26);\n}\n\n.pp-login-submit:hover {\n  transform: translateY(-1px);\n  box-shadow: 0 22px 42px rgba(249, 115, 22, 0.32);\n}\n\n.login-password-toggle {\n  color: var(--pp-blue);\n}\n\n.pp-login-footer-note {\n  margin-top: 18px;\n  padding: 14px;\n  border-radius: 18px;\n  background: #f8fafc;\n  border: 1px solid #e5ebf3;\n  display: grid;\n  gap: 3px;\n}\n\n.pp-login-footer-note strong {\n  color: var(--pp-ink);\n  font-size: 13px;\n}\n\n.pp-login-footer-note span {\n  color: var(--pp-ink-muted);\n  font-size: 12px;\n  line-height: 1.45;\n}\n\n.pp-login-loading {\n  position: relative;\n  z-index: 1;\n  width: min(390px, calc(100vw - 40px));\n  padding: 30px;\n  border-radius: 30px;\n  background: rgba(255,255,255,0.08);\n  border: 1px solid rgba(255,255,255,0.12);\n  display: grid;\n  gap: 18px;\n}\n\n/* Home */\n.page-content {\n  max-width: 1500px;\n  padding: 24px;\n}\n\n.pp-home-hero {\n  position: relative;\n  overflow: hidden;\n  border: 1px solid rgba(15, 23, 42, 0.08);\n  border-radius: 34px;\n  padding: 34px;\n  display: grid;\n  grid-template-columns: minmax(0, 1fr) minmax(360px, 0.7fr);\n  gap: 28px;\n  background:\n    radial-gradient(circle at 15% 5%, rgba(249, 115, 22, 0.17), transparent 36%),\n    radial-gradient(circle at 100% 0%, rgba(37, 99, 235, 0.13), transparent 38%),\n    linear-gradient(135deg, #fff 0%, #f8fafc 100%);\n  box-shadow: var(--pp-shadow);\n}\n\n.pp-home-hero::after {\n  content: \"\";\n  position: absolute;\n  right: -90px;\n  bottom: -120px;\n  width: 280px;\n  height: 280px;\n  border-radius: 999px;\n  background: rgba(249, 115, 22, 0.08);\n}\n\n.pp-home-hero-copy {\n  position: relative;\n  z-index: 1;\n  align-self: center;\n}\n\n.pp-home-hero .page-title {\n  margin-top: 14px;\n  font-size: clamp(36px, 4vw, 62px);\n  line-height: 0.96;\n  letter-spacing: -0.07em;\n  color: var(--pp-ink);\n}\n\n.pp-home-hero .page-subtitle {\n  max-width: 720px;\n  margin-top: 16px;\n  font-size: 16px;\n  color: var(--pp-ink-muted);\n}\n\n.pp-hero-metrics {\n  display: flex;\n  flex-wrap: wrap;\n  gap: 10px;\n  margin-top: 28px;\n}\n\n.pp-hero-metrics span {\n  padding: 10px 13px;\n  border-radius: 999px;\n  background: #fff;\n  border: 1px solid rgba(15, 23, 42, 0.08);\n  box-shadow: 0 10px 24px rgba(15, 23, 42, 0.05);\n  color: var(--pp-ink-muted);\n  font-size: 12px;\n  font-weight: 800;\n}\n\n.pp-hero-metrics strong {\n  color: var(--pp-ink);\n}\n\n.pp-home-command-card {\n  position: relative;\n  z-index: 1;\n  border-radius: 28px;\n  padding: 22px;\n  background: rgba(15, 23, 42, 0.96);\n  color: #fff;\n  box-shadow: 0 25px 70px rgba(15, 23, 42, 0.25);\n}\n\n.pp-command-header {\n  display: flex;\n  justify-content: space-between;\n  gap: 12px;\n  margin-bottom: 15px;\n}\n\n.pp-command-header span {\n  font-size: 16px;\n  font-weight: 900;\n}\n\n.pp-command-header small {\n  color: rgba(255, 255, 255, 0.62);\n  font-weight: 700;\n}\n\n.pp-command-input {\n  border: 1px solid rgba(255, 255, 255, 0.14);\n  background: rgba(255, 255, 255, 0.08);\n  color: #fff;\n}\n\n.pp-command-input::placeholder {\n  color: rgba(255, 255, 255, 0.48);\n}\n\n.pp-command-input:focus {\n  background: rgba(255, 255, 255, 0.12);\n  border-color: rgba(147, 197, 253, 0.72);\n  box-shadow: 0 0 0 4px rgba(37, 99, 235, 0.18);\n}\n\n.pp-command-hint {\n  margin: 12px 0 0;\n  color: rgba(255, 255, 255, 0.62);\n  font-size: 12px;\n  line-height: 1.5;\n}\n\n.pp-search-suggestions {\n  max-height: 330px;\n  overflow: auto;\n}\n\n.pp-section-heading {\n  display: grid;\n  gap: 7px;\n  margin: 0 0 14px;\n}\n\n.pp-section-heading h2 {\n  margin: 0;\n  color: var(--pp-ink);\n  font-size: 25px;\n  letter-spacing: -0.04em;\n}\n\n.pp-action-grid {\n  grid-template-columns: repeat(5, minmax(180px, 1fr));\n}\n\n.pp-action-card {\n  position: relative;\n  min-height: 164px;\n  flex-direction: column;\n  gap: 16px;\n  padding: 20px;\n  border-radius: 26px;\n  overflow: hidden;\n}\n\n.pp-action-card::after {\n  content: \"\";\n  position: absolute;\n  right: -32px;\n  bottom: -42px;\n  width: 100px;\n  height: 100px;\n  border-radius: 999px;\n  background: currentColor;\n  opacity: 0.06;\n}\n\n.pp-action-primary { color: var(--pp-orange); border-color: rgba(249, 115, 22, 0.25); }\n.pp-action-blue { color: var(--pp-blue); border-color: rgba(37, 99, 235, 0.22); }\n.pp-action-green { color: var(--pp-green); border-color: rgba(5, 150, 105, 0.22); }\n.pp-action-violet { color: var(--pp-violet); border-color: rgba(124, 58, 237, 0.22); }\n.pp-action-slate { color: #475569; border-color: rgba(71, 85, 105, 0.2); }\n\n.pp-action-icon {\n  color: currentColor;\n  background: color-mix(in srgb, currentColor 11%, white);\n}\n\n.pp-action-copy {\n  display: grid;\n  gap: 7px;\n  color: var(--pp-ink);\n}\n\n.pp-action-copy strong {\n  font-size: 17px;\n}\n\n.pp-action-copy small {\n  color: var(--pp-ink-muted);\n  font-size: 13px;\n  line-height: 1.45;\n}\n\n.pp-action-arrow {\n  position: absolute;\n  top: 20px;\n  right: 20px;\n  color: currentColor;\n  font-weight: 900;\n}\n\n.pp-card-header {\n  background: #fff;\n}\n\n.pp-card-header h2 {\n  margin-top: 5px;\n  font-size: 22px;\n  letter-spacing: -0.035em;\n  color: var(--pp-ink);\n}\n\n.pp-summary-grid {\n  padding: 20px;\n  display: grid;\n  grid-template-columns: repeat(3, minmax(0, 1fr));\n}\n\n.pp-summary-card {\n  padding: 20px;\n  border-radius: 22px;\n  background:\n    radial-gradient(circle at 100% 0%, rgba(249, 115, 22, 0.12), transparent 38%),\n    #fff;\n  border: 1px solid #edf1f7;\n  display: grid;\n  gap: 8px;\n}\n\n.pp-summary-card strong {\n  font-size: 26px;\n  letter-spacing: -0.04em;\n}\n\n.pp-summary-card small {\n  color: var(--pp-ink-muted);\n  font-weight: 700;\n}\n\n.pp-history-grid {\n  grid-template-columns: repeat(auto-fit, minmax(280px, 1fr));\n}\n\n.pp-history-card {\n  border-radius: 24px;\n  background:\n    linear-gradient(180deg, #fff 0%, #f8fafc 100%);\n  border-color: #e5ebf3;\n}\n\n.pp-history-card:hover {\n  border-color: rgba(249, 115, 22, 0.28);\n}\n\n.pp-history-card-auto {\n  border-color: rgba(37, 99, 235, 0.16);\n}\n\n.pp-empty-state {\n  background:\n    linear-gradient(135deg, #f8fafc, #fff);\n  color: var(--pp-ink-muted);\n}\n\n/* Global cards/forms */\n.control-card,\n.table-card,\n.toolbar,\n.table-panel,\n.home-section {\n  border-radius: var(--pp-radius);\n  border-color: rgba(15, 23, 42, 0.08);\n  box-shadow: var(--pp-shadow-soft);\n}\n\n.btn-primary {\n  background: linear-gradient(135deg, var(--pp-blue), #1d4ed8);\n}\n\n.btn-success {\n  background: linear-gradient(135deg, var(--pp-green), #047857);\n}\n\n.toolbar-actions button,\n.btn {\n  border-radius: 14px;\n}\n\n/* Responsive */\n@media (max-width: 1120px) {\n  .pp-login-layout,\n  .pp-home-hero {\n    grid-template-columns: 1fr;\n  }\n\n  .pp-action-grid {\n    grid-template-columns: repeat(2, minmax(180px, 1fr));\n  }\n\n  .pp-login-module-grid {\n    grid-template-columns: 1fr;\n  }\n\n  .topbar-context {\n    display: none;\n  }\n}\n\n@media (max-width: 720px) {\n  .topbar-site {\n    height: 68px;\n    padding: 0 12px;\n  }\n\n  .pp-topbar-brand .pp-brand-descriptor,\n  .topbar-account-copy {\n    display: none;\n  }\n\n  .pp-login-layout {\n    width: min(100%, calc(100vw - 24px));\n    padding: 24px 0;\n  }\n\n  .pp-login-intro {\n    gap: 20px;\n  }\n\n  .pp-login-hero-copy h1 {\n    font-size: 38px;\n  }\n\n  .pp-login-module-grid,\n  .pp-login-trust-row {\n    display: none;\n  }\n\n  .pp-login-card {\n    padding: 22px;\n    border-radius: 26px;\n  }\n\n  .page-content {\n    padding: 14px;\n  }\n\n  .pp-home-hero {\n    padding: 22px;\n    border-radius: 26px;\n  }\n\n  .pp-home-hero .page-title {\n    font-size: 38px;\n  }\n\n  .pp-action-grid,\n  .pp-summary-grid {\n    grid-template-columns: 1fr;\n  }\n\n  .sidebar {\n    width: min(330px, 92vw);\n  }\n}\n");
write("docs/PROMOPILOT_PRODUCT_UI_V2.md", "# PromoPilot Product UI V2\n\nRemodela\u00e7\u00e3o visual e funcional de produto para o `main`.\n\n## Objetivo\n\nDeixar o SaaS com identidade PromoPilot e uma interface mais s\u00e9nior, profissional e \u00fatil para loja.\n\n## O que muda\n\n- Identidade centralizada em `src/brand/promopilot.js`\n- Marca visual pr\u00f3pria em `src/components/brand/PromoPilotMark.jsx`\n- Splash screen PromoPilot\n- Login redesenhado como landing operacional\n- Topbar e sidebar redesenhadas\n- Homepage convertida em cockpit operacional\n- A\u00e7\u00f5es r\u00e1pidas mais claras:\n  - Criar campanha\n  - Cat\u00e1logo de artigos\n  - Scan em loja\n  - Dossiers de or\u00e7amento\n  - Importa\u00e7\u00e3o Excel\n- Hist\u00f3rico e resumo com apresenta\u00e7\u00e3o mais limpa\n- Camada visual moderna em `src/styles/promopilot.css`\n\n## O que n\u00e3o muda\n\nA l\u00f3gica de neg\u00f3cio continua intacta:\n\n- Etiquetas de campanha\n- Cat\u00e1logo e scan\n- Importa\u00e7\u00e3o Excel\n- Or\u00e7amentos / Dossiers\n- Autentica\u00e7\u00e3o\n- Migra\u00e7\u00e3o de artigos\n\n## Aplicar\n\n```bash\ncd ~/simaoopp/ETIQUETASPROM\n\nnode scripts/maintenance/apply-promopilot-product-ui-v2.mjs\nnpm run build\n```\n\n## Validar no browser\n\n- Login aparece como PromoPilot\n- Homepage tem cockpit operacional\n- Menu lateral abre e fecha\n- Criar campanha abre corretamente\n- Cat\u00e1logo abre corretamente\n- Dossiers abre corretamente\n- Importa\u00e7\u00e3o Excel abre corretamente\n- Mobile mant\u00e9m layout utiliz\u00e1vel\n\n## Commit sugerido\n\n```bash\ngit add src/App.js \\\n        src/brand/promopilot.js \\\n        src/components/brand/PromoPilotMark.jsx \\\n        src/components/Sidebar.jsx \\\n        src/pages/Login.jsx \\\n        src/pages/Homepage.jsx \\\n        src/components/home/HomeHero.jsx \\\n        src/components/home/HomeQuickActions.jsx \\\n        src/components/home/HomeSummarySection.jsx \\\n        src/components/home/HomeHistorySection.jsx \\\n        src/components/home/HomeAutomaticCampaignHistorySection.jsx \\\n        src/styles/styles.css \\\n        src/styles/promopilot.css \\\n        scripts/maintenance/apply-promopilot-product-ui-v2.mjs \\\n        docs/PROMOPILOT_PRODUCT_UI_V2.md\n\ngit commit -m \"feat: redesign main interface for PromoPilot\"\ngit push origin main\n```\n");

